        var cy5 = my + ny * apothem5;

        var r5 = polygon(5, cx5, cy5);
        var ring5Ordered = reorderToMatch(r5, shared1, shared2);

        var ns = atoms.length;
        // Imidazole portion: C, N, N
        atoms.push({ symbol: 'C', x: ring5Ordered[2].x, y: ring5Ordered[2].y }); // 6
