                padF(a.x / 30, 10, 4) + padF(-a.y / 30, 10, 4) + padF(0, 10, 4) + ' ' +
                padR(a.symbol, 3) + ' 0' +
                pad(chargeToMol(a.charge), 3) + '  0  0  0  0  0  0  0' + pad(aam, 3) + '  0'
