        var n = 0;
        if ((x & 0x0000FFFF) === 0) { n += 16; x >>>= 16; }
        if ((x & 0x000000FF) === 0) { n += 8;  x >>>= 8;  }
        if ((x & 0x0000000F) === 0) { n += 4;  x >>>= 4;  }
