        for (key in cv1) {
            if (cv1.hasOwnProperty(key)) {
                var a = cv1[key];
                sumA += a;
                if (cv2.hasOwnProperty(key)) {
                    sumMin += (a < cv2[key] ? a : cv2[key]);
                }
            }
        }
        for (key in cv2) {
            if (cv2.hasOwnProperty(key)) {
                sumB += cv2[key];
            }
        }
        var denom = sumA + sumB - sumMin;
        return denom === 0 ? 1.0 : sumMin / denom;
